const { Client } = require('pg');
async function tryConnect(host, port, user, password, database) {
  const client = new Client({ host, port, user, password, database, ssl: false });
  try {
    await client.connect();
    const res = await client.query('SELECT 1 AS test');
    console.log('SUCCESS:', { host, port, user, database }, JSON.stringify(res.rows));
    await client.end();
    return true;
  } catch(e) {
    console.log('FAIL:', { host, port, user, database }, e.message);
    try { await client.end(); } catch(_) {}
    return false;
  }
}

