       .from('members')
       .select('*')
       .eq('id', userId)
       .single()
     setProfile(data)
   }

   async function signIn(email, password) {
     return supabase.auth.signInWithPassword({ email, password })
   }

   async function signOut() {
     await supabase.auth.signOut()
     setUser(null)
     setProfile(null)
   }

   return (
